export const getDeviceLanguage = (): AppLanguage => {
  const languageCode = Localization.getLocales()[0]?.languageCode;
  return SUPPORTED_LANGUAGES.some((language) => language.code === languageCode) ? languageCode as AppLanguage : 'en';
};

export const getLanguageMeta = (code: AppLanguage) => SUPPORTED_LANGUAGES.find((language) => language.code === code) ?? SUPPORTED_LANGUAGES[1];

export const changeAppLanguage = async (language: AppLanguage) => {
  await i18n.changeLanguage(language);
};

void i18n
  .use(initReactI18next)
  .init({
    resources,
    lng: getDeviceLanguage(),
    fallbackLng: 'en',
    interpolation: { escapeValue: false }
  });

export default i18n;
